sql:
SELECT AVG(compound) AS average_positive_score
FROM reviews
WHERE label = 'positive';

SELECT AVG(likes) AS average_likes_per_review
FROM reviews
WHERE album_id = 1;

external_knowledge:
- Non-administrative community members refers to users where is_admin = 0; 
- Average sentiment scores refers to the average compound score of reviews; 
- Flagged contributions are reviews where is_flagged = 1.

sql:
SELECT album_id 
FROM review_statistics 
WHERE average_compound_score = (SELECT MAX(average_compound_score) FROM review_statistics);

SELECT DISTINCT a.album_title, a.track_count 
FROM albums a
INNER JOIN reviews r ON a.album_id = r.album_id;

SELECT album_id, average_compound_score
FROM review_statistics
ORDER BY average_compound_score DESC;
